// And groups predicates with the AND operator between them.
func And(predicates ...predicate.MarketplaceItem) predicate.MarketplaceItem {
	return predicate.MarketplaceItem(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.MarketplaceItem) predicate.MarketplaceItem {
	return predicate.MarketplaceItem(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.MarketplaceItem) predicate.MarketplaceItem {
	return predicate.MarketplaceItem(sql.NotPredicates(p))
}
